/**
 * Client-side inventory optimization service
 * Handles cache warming, batch requests, and performance optimization
 */

interface InventoryOptimizationOptions {
  enablePreWarming?: boolean
  batchSize?: number
  warmCacheThreshold?: number // Number of views before pre-warming
  maxRetries?: number
}

interface ProductView {
  variantId: string
  timestamp: number
  viewCount: number
}

class InventoryOptimizationService {
  private viewTracker = new Map<string, ProductView>()
  private warmingQueue = new Set<string>()
  private options: Required<InventoryOptimizationOptions>
  
  constructor(options: InventoryOptimizationOptions = {}) {
    this.options = {
      enablePreWarming: options.enablePreWarming ?? true,
      batchSize: options.batchSize ?? 10,
      warmCacheThreshold: options.warmCacheThreshold ?? 3,
      maxRetries: options.maxRetries ?? 2
    }
    
    // Only initialize browser-dependent features when in browser environment
    if (typeof window !== 'undefined') {
      // Load view tracker from localStorage (safe for Incognito mode)
      this.loadViewTracker()
      
      // Periodic cleanup and optimization
      setInterval(() => this.performMaintenance(), 5 * 60 * 1000) // 5 minutes
    }
  }

  /**
   * Track product view and potentially trigger cache warming
   */
  trackProductView(variantId: string) {
    const existing = this.viewTracker.get(variantId)
    const now = Date.now()
    
    if (existing) {
      existing.viewCount++
      existing.timestamp = now
    } else {
      this.viewTracker.set(variantId, {
        variantId,
        timestamp: now,
        viewCount: 1
      })
    }
    
    // Check if we should pre-warm cache
    if (this.options.enablePreWarming && existing && existing.viewCount >= this.options.warmCacheThreshold) {
      this.scheduleWarmCache(variantId)
    }
    
    // Persist to localStorage (debounced)
    this.saveViewTracker()
  }

  /**
   * Get hot products that should have their cache warmed
   */
  getHotProducts(limit: number = 20): string[] {
    const now = Date.now()
    const oneHour = 60 * 60 * 1000
    
    return Array.from(this.viewTracker.values())
      .filter(view => now - view.timestamp < oneHour) // Only recent views
      .sort((a, b) => b.viewCount - a.viewCount)
      .slice(0, limit)
      .map(view => view.variantId)
  }

  /**
   * Batch warm cache for multiple variants
   */
  async warmCache(variantIds: string[]): Promise<void> {
    if (variantIds.length === 0) return
    
    const batches = this.createBatches(variantIds, this.options.batchSize)
    
    for (const batch of batches) {
      try {
        await this.warmCacheBatch(batch)
      } catch (error) {
        console.error('Failed to warm cache batch:', error)
      }
    }
  }

  /**
   * Batch check inventory for multiple variants with optimization
   */
  async batchCheckInventory(variantIds: string[]): Promise<Map<string, any>> {
    const results = new Map<string, any>()
    
    if (variantIds.length === 0) return results
    
    const batches = this.createBatches([...new Set(variantIds)], this.options.batchSize)
    
    const batchPromises = batches.map(async (batch, index) => {
      // Stagger requests to avoid overwhelming the API
      await new Promise(resolve => setTimeout(resolve, index * 100))
      
      return this.checkInventoryBatch(batch)
    })
    
    const batchResults = await Promise.allSettled(batchPromises)
    
    batchResults.forEach(result => {
      if (result.status === 'fulfilled') {
        result.value.forEach((value, key) => {
          results.set(key, value)
        })
      }
    })
    
    return results
  }

  /**
   * Invalidate cache for specific variants after purchase/update
   */
  async invalidateCache(variantIds: string[]): Promise<void> {
    if (variantIds.length === 0) return
    
    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/commerce-integration/inventory/invalidate`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ variantIds }),
          signal: AbortSignal.timeout(10000)
        }
      )
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`)
      }
      
      console.log(`Cache invalidated for ${variantIds.length} variants`)
    } catch (error) {
      console.error('Failed to invalidate cache:', error)
      throw error
    }
  }

  /**
   * Get service statistics
   */
  getStats(): {
    trackedProducts: number
    hotProducts: number
    queueSize: number
    topProducts: Array<{ variantId: string; views: number }>
  } {
    const hotProducts = this.getHotProducts()
    const topProducts = Array.from(this.viewTracker.values())
      .sort((a, b) => b.viewCount - a.viewCount)
      .slice(0, 5)
      .map(view => ({ variantId: view.variantId, views: view.viewCount }))
    
    return {
      trackedProducts: this.viewTracker.size,
      hotProducts: hotProducts.length,
      queueSize: this.warmingQueue.size,
      topProducts
    }
  }

  // Private methods

  private scheduleWarmCache(variantId: string) {
    if (this.warmingQueue.has(variantId)) return
    
    this.warmingQueue.add(variantId)
    
    // Debounced warming
    setTimeout(() => {
      this.warmCache([variantId])
      this.warmingQueue.delete(variantId)
    }, 1000)
  }

  private async warmCacheBatch(variantIds: string[]): Promise<void> {
    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/commerce-integration/inventory/prewarm`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ variantIds }),
          signal: AbortSignal.timeout(15000)
        }
      )
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`)
      }
      
      console.log(`Cache warmed for ${variantIds.length} variants`)
    } catch (error) {
      console.error('Failed to warm cache batch:', error)
      throw error
    }
  }

  private async checkInventoryBatch(variantIds: string[]): Promise<Map<string, any>> {
    const results = new Map<string, any>()
    
    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/commerce-integration/inventory/check`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ 
            variantIds, 
            useCache: true, 
            includeLocations: false 
          }),
          signal: AbortSignal.timeout(15000)
        }
      )
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`)
      }
      
      const result = await response.json()
      
      if (result.success && result.data) {
        Object.entries(result.data).forEach(([variantId, data]) => {
          results.set(variantId, data)
        })
      }
    } catch (error) {
      console.error('Failed to check inventory batch:', error)
      // Return empty results rather than throwing to avoid breaking UI
    }
    
    return results
  }

  private createBatches<T>(items: T[], batchSize: number): T[][] {
    const batches: T[][] = []
    for (let i = 0; i < items.length; i += batchSize) {
      batches.push(items.slice(i, i + batchSize))
    }
    return batches
  }

  private loadViewTracker() {
    // Skip if not in browser environment or localStorage not available
    if (typeof window === 'undefined' || typeof localStorage === 'undefined') {
      return
    }
    
    try {
      const stored = localStorage.getItem('sidedecked_product_views')
      if (stored) {
        const data = JSON.parse(stored)
        // Only load recent data (last 24 hours)
        const cutoff = Date.now() - 24 * 60 * 60 * 1000
        Object.entries(data).forEach(([variantId, view]: [string, any]) => {
          if (view.timestamp > cutoff) {
            this.viewTracker.set(variantId, view)
          }
        })
      }
    } catch (error) {
      // Gracefully handle localStorage errors (e.g., Incognito mode restrictions)
      console.warn('Failed to load view tracker (localStorage not available):', error)
    }
  }

  private saveViewTracker = this.debounce(() => {
    // Skip if not in browser environment or localStorage not available
    if (typeof window === 'undefined' || typeof localStorage === 'undefined') {
      return
    }
    
    try {
      const data = Object.fromEntries(this.viewTracker)
      localStorage.setItem('sidedecked_product_views', JSON.stringify(data))
    } catch (error) {
      // Gracefully handle localStorage errors (e.g., Incognito mode restrictions)
      console.warn('Failed to save view tracker (localStorage not available):', error)
    }
  }, 1000)

  private performMaintenance() {
    const now = Date.now()
    const oneDay = 24 * 60 * 60 * 1000
    
    // Remove old tracking data
    this.viewTracker.forEach((view, variantId) => {
      if (now - view.timestamp > oneDay) {
        this.viewTracker.delete(variantId)
      }
    })
    
    // Warm cache for hot products
    if (this.options.enablePreWarming) {
      const hotProducts = this.getHotProducts(10)
      if (hotProducts.length > 0) {
        this.warmCache(hotProducts)
      }
    }
    
    this.saveViewTracker()
  }

  private debounce<T extends (...args: any[]) => any>(func: T, delay: number): T {
    let timeoutId: NodeJS.Timeout | null = null
    return ((...args: any[]) => {
      if (timeoutId !== null) {
        clearTimeout(timeoutId)
      }
      timeoutId = setTimeout(() => func(...args), delay)
    }) as T
  }
}

// Global instance
export const inventoryOptimizer = new InventoryOptimizationService()

// Export for use in components
export { InventoryOptimizationService }
export type { InventoryOptimizationOptions, ProductView }

import { HttpTypes } from '@medusajs/types'

export interface EnrichedCartItem {
  // Standard Medusa cart item
  id: string
  cart_id: string
  product_id: string
  variant_id: string
  quantity: number
  unit_price: number
  total: number
  title: string
  variant_title?: string | null
  
  // TCG enrichment data
  catalog_enrichment?: {
    catalog_sku: string
    condition: string
    language: string
    finish: string
    card: {
      id: string
      name: string
      oracle_text?: string
      flavor_text?: string
      mana_cost?: string
      mana_value?: number
      colors?: string[]
      power_value?: number
      defense_value?: number
      hp?: number
      primary_type?: string
      subtypes?: string[]
    }
    print: {
      rarity: string
      artist: string
      image_normal?: string
      image_small?: string
    }
    set: {
      name: string
      code: string
    }
    game: {
      code: string
      name: string
    }
  }
  
  // Seller information
  seller_info?: {
    id: string
    name: string
    handle: string
    type: 'business_vendor' | 'consumer_seller'
    rating?: number
    total_reviews?: number
    verified: boolean
  }
}

export interface EnrichedCart {
  id: string
  customer_id?: string
  items: EnrichedCartItem[]
  
  // Seller grouping for multi-seller checkout
  seller_groups: Array<{
    seller_id: string
    seller_type: 'business_vendor' | 'consumer_seller'
    seller_name: string
    seller_rating?: number
    items: EnrichedCartItem[]
    subtotal: number
    item_count: number
  }>
  
  // Enhanced totals
  totals: {
    subtotal: number
    tax_total: number
    shipping_total: number
    total: number
    item_count: number
    unique_sellers: number
  }
}

class CartEnrichmentService {
  private customerBackendUrl: string

  constructor() {
    this.customerBackendUrl = process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL || 'http://localhost:7000'
  }

  /**
   * Enrich cart with TCG catalog data and seller information
   */
  async enrichCart(cart: HttpTypes.StoreCart): Promise<EnrichedCart> {
    try {
      // Extract SKUs from cart items
      const skus = cart.items?.map(item => item.variant?.sku).filter((sku): sku is string => Boolean(sku)) || []
      
      // Get catalog enrichment data
      const catalogData = await this.getCatalogEnrichment(skus)
      
      // Get seller information
      const sellerData = await this.getSellerInformation(cart.items || [])
      
      // Enrich cart items
      const enrichedItems: EnrichedCartItem[] = (cart.items || []).map(item => {
        const sku = item.variant?.sku
        const enrichment = sku ? catalogData[sku] : null
        const sellerInfo = sellerData[(item.variant?.product as any)?.seller_id || '']
        
        return {
          id: item.id!,
          cart_id: cart.id!,
          product_id: item.product_id!,
          variant_id: item.variant_id!,
          quantity: item.quantity!,
          unit_price: item.unit_price!,
          total: item.total!,
          title: item.title!,
          variant_title: item.variant?.title,
          catalog_enrichment: enrichment && enrichment.valid ? enrichment : undefined,
          seller_info: sellerInfo
        }
      })
      
      // Group items by seller
      const sellerGroups = this.groupItemsBySeller(enrichedItems)
      
      // Calculate enhanced totals
      const totals = this.calculateEnhancedTotals(cart, enrichedItems, sellerGroups)
      
      return {
        id: cart.id!,
        customer_id: cart.customer_id,
        items: enrichedItems,
        seller_groups: sellerGroups,
        totals
      }
    } catch (error) {
      console.error('Error enriching cart:', error)
      
      // Return basic enriched cart on error
      return {
        id: cart.id!,
        customer_id: cart.customer_id,
        items: (cart.items || []).map(item => ({
          id: item.id!,
          cart_id: cart.id!,
          product_id: item.product_id!,
          variant_id: item.variant_id!,
          quantity: item.quantity!,
          unit_price: item.unit_price!,
          total: item.total!,
          title: item.title!,
          variant_title: item.variant?.title
        })),
        seller_groups: [],
        totals: {
          subtotal: cart.subtotal || 0,
          tax_total: cart.tax_total || 0,
          shipping_total: cart.shipping_total || 0,
          total: cart.total || 0,
          item_count: cart.items?.length || 0,
          unique_sellers: 0
        }
      }
    }
  }

  /**
   * Get catalog enrichment data for SKUs
   */
  private async getCatalogEnrichment(skus: string[]): Promise<Record<string, any>> {
    if (skus.length === 0) return {}
    
    try {
      const response = await fetch(`${this.customerBackendUrl}/api/commerce-integration/validate-sku`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ skus })
      })
      
      if (!response.ok) {
        console.error('Failed to get catalog enrichment:', response.statusText)
        return {}
      }
      
      const result = await response.json()
      return result.success ? result.data : {}
    } catch (error) {
      console.error('Error fetching catalog enrichment:', error)
      return {}
    }
  }

  /**
   * Get seller information for cart items
   */
  private async getSellerInformation(items: HttpTypes.StoreCartLineItem[]): Promise<Record<string, any>> {
    // Extract unique seller IDs
    const sellerIds = [...new Set(
      items
        .map(item => (item.variant?.product as any)?.seller_id)
        .filter(Boolean)
    )]
    
    if (sellerIds.length === 0) return {}
    
    try {
      // TODO: This would call the backend seller API
      // For now, return mock data
      const sellerData: Record<string, any> = {}
      
      sellerIds.forEach(sellerId => {
        sellerData[sellerId] = {
          id: sellerId,
          name: `Seller ${sellerId.slice(-4)}`,
          handle: `seller-${sellerId.slice(-4)}`,
          type: Math.random() > 0.7 ? 'consumer_seller' : 'business_vendor',
          rating: 4.0 + Math.random(),
          total_reviews: Math.floor(Math.random() * 100) + 10,
          verified: Math.random() > 0.3
        }
      })
      
      return sellerData
    } catch (error) {
      console.error('Error fetching seller information:', error)
      return {}
    }
  }

  /**
   * Group cart items by seller
   */
  private groupItemsBySeller(items: EnrichedCartItem[]) {
    const groups: Record<string, {
      seller_id: string
      seller_type: 'business_vendor' | 'consumer_seller'
      seller_name: string
      seller_rating?: number
      items: EnrichedCartItem[]
      subtotal: number
      item_count: number
    }> = {}
    
    items.forEach(item => {
      const sellerId = item.seller_info?.id || 'unknown'
      
      if (!groups[sellerId]) {
        groups[sellerId] = {
          seller_id: sellerId,
          seller_type: item.seller_info?.type || 'business_vendor',
          seller_name: item.seller_info?.name || 'Unknown Seller',
          seller_rating: item.seller_info?.rating,
          items: [],
          subtotal: 0,
          item_count: 0
        }
      }
      
      groups[sellerId].items.push(item)
      groups[sellerId].subtotal += item.total
      groups[sellerId].item_count += item.quantity
    })
    
    return Object.values(groups)
  }

  /**
   * Calculate enhanced totals
   */
  private calculateEnhancedTotals(
    cart: HttpTypes.StoreCart, 
    items: EnrichedCartItem[], 
    sellerGroups: any[]
  ) {
    return {
      subtotal: cart.subtotal || 0,
      tax_total: cart.tax_total || 0,
      shipping_total: cart.shipping_total || 0,
      total: cart.total || 0,
      item_count: items.reduce((sum, item) => sum + item.quantity, 0),
      unique_sellers: sellerGroups.length
    }
  }

  /**
   * Validate cart items against inventory
   */
  async validateCartInventory(cartItems: EnrichedCartItem[]): Promise<Record<string, boolean>> {
    const variantIds = cartItems.map(item => item.variant_id)
    
    if (variantIds.length === 0) return {}
    
    try {
      const response = await fetch(`${this.customerBackendUrl}/api/commerce-integration/inventory/check`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          variantIds,
          useCache: true,
          includeLocations: false
        })
      })
      
      if (!response.ok) {
        console.error('Failed to validate inventory:', response.statusText)
        return {}
      }
      
      const result = await response.json()
      
      if (!result.success) return {}
      
      // Convert inventory data to availability flags
      const availability: Record<string, boolean> = {}
      Object.entries(result.data).forEach(([variantId, inventoryData]: [string, any]) => {
        availability[variantId] = inventoryData.available_quantity > 0
      })
      
      return availability
    } catch (error) {
      console.error('Error validating cart inventory:', error)
      return {}
    }
  }
}

export const cartEnrichmentService = new CartEnrichmentService()
export default cartEnrichmentService

'use client'

import React, { createContext, useContext, useState, useCallback, useEffect, useRef } from 'react'
import { Deck, DeckCard, DeckValidation, DeckStats, DeckFormat } from '@/types/deck'
import { useFeedback } from '@/hooks/useFeedback'
import { validateDeck, useRealtimeDeckValidation, GAME_FORMATS } from '@/lib/validation/deck-validation'
import { useCustomer } from '@/hooks/useCustomer'
import { getGames } from '@/lib/data/cards'
import { customerBackendAPI } from '@/lib/api/customer-backend'

interface DeckBuilderContextValue {
  deck: Deck | null
  isDirty: boolean
  isLoading: boolean
  isSaving: boolean
  validation: DeckValidation
  stats: DeckStats
  format: DeckFormat | null
  
  // Deck operations
  loadDeck: (deckId: string) => Promise<void>
  loadDeckForEdit: (deckId: string) => Promise<void>
  createDeck: (name: string, game: string, format: string) => Promise<void>
  saveDeck: () => Promise<void>
  deleteDeck: () => Promise<void>
  
  // Card operations
  addCard: (card: any, zone: 'main' | 'sideboard' | 'commander' | 'extra' | 'leader' | 'don' | 'prize', quantity?: number) => void
  removeCard: (catalogSku: string, zone: string, quantity?: number) => void
  moveCard: (catalogSku: string, fromZone: string, toZone: string, quantity?: number) => void
  updateCardQuantity: (catalogSku: string, zone: string, newQuantity: number) => void
  
  // Deck metadata
  updateDeckName: (name: string) => void
  updateDeckDescription: (description: string) => void
  togglePublicVisibility: () => void
  
  // Validation
  validateDeck: () => void
  getFormatRules: () => DeckFormat | null
  realtimeValidation: ReturnType<typeof useRealtimeDeckValidation>
  
  // Import/Export
  importDeck: (format: string, data: string) => Promise<void>
  exportDeck: (format: string) => Promise<string>
  
  // Undo/Redo
  canUndo: boolean
  canRedo: boolean
  undo: () => void
  redo: () => void
  
  // Clear/Reset
  clearDeck: () => void
  resetDeck: () => void
}

const DeckBuilderContext = createContext<DeckBuilderContextValue | undefined>(undefined)

export function DeckBuilderProvider({ children }: { children: React.ReactNode }) {
  const [deck, setDeck] = useState<Deck | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [isSaving, setIsSaving] = useState(false)
  const [validation, setValidation] = useState<DeckValidation>({ isValid: true, errors: [] })
  const realtimeValidation = useRealtimeDeckValidation(deck)
  const [stats, setStats] = useState<DeckStats>({
    totalCards: 0,
    mainDeckSize: 0,
    sideboardSize: 0,
  })
  const [format, setFormat] = useState<DeckFormat | null>(null)
  
  // Undo/Redo history
  const [history, setHistory] = useState<Deck[]>([])
  const [historyIndex, setHistoryIndex] = useState(-1)
  const autoSaveTimer = useRef<NodeJS.Timeout | null>(null)
  
  const { executeWithFeedback } = useFeedback('deck-builder')
  const { customer, isAuthenticated } = useCustomer()
  
  // Calculate stats whenever deck changes
  useEffect(() => {
    if (!deck) return
    
    const newStats = calculateDeckStats(deck)
    setStats(newStats)
    
    // Auto-validate on changes using new validation system
    const newValidation = validateDeck(deck)
    setValidation({
      isValid: newValidation.isValid,
      errors: newValidation.errors.map(error => ({
        zone: error.zone || 'main',
        type: error.category,
        message: error.message,
        cardSku: error.cardSku
      })),
      warnings: newValidation.warnings.map(warning => ({
        zone: warning.zone || 'main', 
        type: warning.category,
        message: warning.message,
        cardSku: warning.cardSku
      }))
    })
    
    // Update format rules
    if (deck.game && deck.format) {
      const gameFormats = GAME_FORMATS[deck.game as keyof typeof GAME_FORMATS] as any
      const formatRules = gameFormats?.[deck.format] as any
      if (formatRules) {
        setFormat({
          name: deck.format,
          game: deck.game,
          minDeckSize: formatRules.minDeckSize,
          maxDeckSize: formatRules.maxDeckSize || undefined,
          sideboardSize: formatRules.sideboardSize || 0,
          maxCopies: formatRules.maxCopies,
          bannedCards: formatRules.bannedCards || [],
          restrictedCards: formatRules.restrictedCards || []
        })
      }
    }
  }, [deck, format]) // eslint-disable-line react-hooks/exhaustive-deps
  
  // Auto-save functionality
  useEffect(() => {
    if (isDirty && deck?.id) {
      if (autoSaveTimer.current) {
        clearTimeout(autoSaveTimer.current)
      }
      
      autoSaveTimer.current = setTimeout(() => {
        saveDeck()
      }, 3000) // Auto-save after 3 seconds of inactivity
    }
    
    return () => {
      if (autoSaveTimer.current) {
        clearTimeout(autoSaveTimer.current)
      }
    }
  }, [isDirty, deck]) // eslint-disable-line react-hooks/exhaustive-deps
  
  const calculateDeckStats = useCallback((deck: Deck): DeckStats => {
    const stats: DeckStats = {
      totalCards: 0,
      mainDeckSize: 0,
      sideboardSize: 0,
      commanderSize: 0,
      extraDeckSize: 0,
      leaderSize: 0,
      donDeckSize: 0,
      prizeCardCount: 0,
      averageCmc: 0,
      manaCurve: {},
      colorDistribution: {},
      typeDistribution: {},
      rarityDistribution: {},
    }
    
    // Calculate main deck stats
    deck.cards.main.forEach(card => {
      stats.mainDeckSize += card.quantity
      stats.totalCards += card.quantity
      
      // Mana curve (MTG specific)
      if (card.card.cmc !== undefined) {
        const cmc = Math.min(card.card.cmc, 7) // Group 7+ together
        stats.manaCurve![cmc] = (stats.manaCurve![cmc] || 0) + card.quantity
      }
      
      // Colors
      if (card.card.colors) {
        card.card.colors.forEach(color => {
          stats.colorDistribution![color] = (stats.colorDistribution![color] || 0) + card.quantity
        })
      }
      
      // Types
      if (card.card.type_line) {
        const mainType = card.card.type_line.split(' — ')[0]
        stats.typeDistribution![mainType] = (stats.typeDistribution![mainType] || 0) + card.quantity
      }
      
      // Rarity
      if (card.card.rarity) {
        stats.rarityDistribution![card.card.rarity] = 
          (stats.rarityDistribution![card.card.rarity] || 0) + card.quantity
      }
    })
    
    // Calculate sideboard stats
    if (deck.cards.sideboard) {
      deck.cards.sideboard.forEach(card => {
        stats.sideboardSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate commander stats
    if (deck.cards.commander) {
      deck.cards.commander.forEach(card => {
        stats.commanderSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate extra deck stats
    if (deck.cards.extra) {
      deck.cards.extra.forEach(card => {
        stats.extraDeckSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate leader stats
    if (deck.cards.leader) {
      deck.cards.leader.forEach(card => {
        stats.leaderSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate DON!! deck stats
    if (deck.cards.don) {
      deck.cards.don.forEach(card => {
        stats.donDeckSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate prize card stats
    if (deck.cards.prize) {
      deck.cards.prize.forEach(card => {
        stats.prizeCardCount! += card.quantity
        stats.totalCards += card.quantity
      })
    }
    
    // Calculate average CMC
    if (stats.manaCurve && Object.keys(stats.manaCurve).length > 0) {
      let totalCmc = 0
      let totalCards = 0
      Object.entries(stats.manaCurve).forEach(([cmc, count]) => {
        totalCmc += parseInt(cmc) * count
        totalCards += count
      })
      stats.averageCmc = totalCards > 0 ? totalCmc / totalCards : 0
    }
    
    return stats
  }, [])
  
