        const defaultFormats: { [key: string]: string } = {
          'MTG': 'Standard',
          'POKEMON': 'Standard',
          'YUGIOH': 'Advanced',
          'OPTCG': 'Standard'
        }
        
        const finalFormat = format && format !== 'undefined' ? format : defaultFormats[game] || 'Standard'
        
