  return await sdk.client.fetch<{
    shipping_options: HttpTypes.StoreCartShippingOption[]
  }>("/store/shipping-options", {
    query: { cart_id: cartId },
    next,
    headers,
    cache: "force-cache",
  })
}

/**
 * Retrieves an enriched cart with TCG catalog data and seller information
 * @param cartId - optional - The ID of the cart to retrieve
 * @returns Enriched cart with catalog data and seller grouping
 */
export async function retrieveEnrichedCart(cartId?: string): Promise<EnrichedCart | null> {
  const cart = await retrieveCart(cartId)
  
  if (!cart) {
    return null
  }
  
  try {
    return await cartEnrichmentService.enrichCart(cart)
  } catch (error) {
    console.error('Error enriching cart:', error)
    // Return basic cart structure as fallback
    return {
      id: cart.id!,
      customer_id: cart.customer_id,
      items: (cart.items || []).map(item => ({
        id: item.id!,
        cart_id: cart.id!,
        product_id: item.product_id!,
