      })),
      seller_groups: [],
      totals: {
        subtotal: cart.subtotal || 0,
        tax_total: cart.tax_total || 0,
        shipping_total: cart.shipping_total || 0,
        total: cart.total || 0,
        item_count: cart.items?.length || 0,
        unique_sellers: 0
      }
    }
  }
}

