import { AuthenticatedMedusaRequest, MedusaResponse } from '@medusajs/framework/http'
import { ContainerRegistrationKeys, ProductStatus, toHandle } from '@medusajs/framework/utils'
import { createProductsWorkflow } from '@medusajs/medusa/core-flows'

import { StoreCreateConsumerSellerListingType } from '../validators'
import { fetchConsumerSellerByCustomerId } from '../payout-account/utils'

/**
 * @oas [get] /store/consumer-seller/listings
 * operationId: "GetConsumerSellerListings"
 * summary: "List consumer seller's products"
 * description: "Returns paginated product listings for the authenticated consumer seller."
 * x-authenticated: true
 * parameters:
 *   - name: status
 *     in: query
 *     schema:
 *       type: string
 *       enum: [published, draft, all]
 *     description: Filter by product status
 *   - name: limit
 *     in: query
 *     schema:
 *       type: number
 *       default: 20
 *   - name: offset
 *     in: query
 *     schema:
 *       type: number
 *       default: 0
 * responses:
 *   "200":
 *     description: OK
 *   "404":
 *     description: Not a seller
 * tags:
 *   - Consumer Seller Listings
 */
export const GET = async (
  req: AuthenticatedMedusaRequest,
  res: MedusaResponse
) => {
  const customerId = req.auth_context.actor_id
  const logger = req.scope.resolve(ContainerRegistrationKeys.LOGGER)

  try {
    const query = req.scope.resolve(ContainerRegistrationKeys.QUERY)

    const seller = await fetchConsumerSellerByCustomerId(customerId, req.scope)
    const statusParam = (req.query.status as string) || 'all'
    const allowedStatuses = ['published', 'draft', 'all'] as const
    if (!allowedStatuses.includes(statusParam as (typeof allowedStatuses)[number])) {
      return res.status(400).json({
        success: false,
        message: 'Invalid status value. Allowed values are: published, draft, all.',
      })
    }
    const status = statusParam
    const rawLimit = parseInt(req.query.limit as string, 10)
    const limit = Math.min(Math.max(Number.isNaN(rawLimit) ? 20 : rawLimit, 1), 100)
    const rawOffset = parseInt(req.query.offset as string, 10)
    const offset = Math.max(Number.isNaN(rawOffset) ? 0 : rawOffset, 0)

    const filters: any = { seller_id: seller.id }
    if (status !== 'all') {
      filters.status = status
    }

    const { data: products, metadata } = await query.graph({
      entity: 'product',
      fields: [
        'id',
        'title',
        'handle',
        'status',
        'thumbnail',
        'created_at',
        'updated_at',
        'variants.id',
        'variants.title',
        'variants.sku',
        'variants.prices.amount',
        'variants.prices.currency_code',
        'variants.manage_inventory',
      ],
      filters,
      pagination: {
        skip: offset,
        take: limit,
        order: { created_at: 'DESC' },
      },
    })

    return res.json({
      success: true,
      data: {
        listings: products.map((p: any) => ({
          id: p.id,
          title: p.title,
          handle: p.handle,
          status: p.status,
          thumbnail: p.thumbnail,
          created_at: p.created_at,
          updated_at: p.updated_at,
          variants: (p.variants || []).map((v: any) => ({
            id: v.id,
            title: v.title,
            sku: v.sku,
            price: v.prices?.[0]?.amount ?? 0,
            currency_code: v.prices?.[0]?.currency_code ?? 'usd',
          })),
        })),
        total: metadata?.count ?? products.length,
        limit,
        offset,
      },
    })
  } catch (error: any) {
    logger.error(`[consumer-seller/listings] Error: ${error?.message}`)
    if (error?.type === 'not_found') {
      return res.status(404).json({
        success: false,
        message: 'Customer is not registered as a seller',
      })
    }
    return res.status(500).json({
      success: false,
      message: 'Failed to load listings',
    })
  }
}

