 *           status:
 *             type: string
 *             enum: [published, draft]
 *             default: published
 * responses:
 *   "201":
 *     description: Created
 *   "404":
 *     description: Not a seller
 * tags:
 *   - Consumer Seller Listings
 */
export const POST = async (
  req: AuthenticatedMedusaRequest<StoreCreateConsumerSellerListingType>,
  res: MedusaResponse
) => {
  const customerId = req.auth_context.actor_id
  const logger = req.scope.resolve(ContainerRegistrationKeys.LOGGER)

  try {
    const seller = await fetchConsumerSellerByCustomerId(customerId, req.scope)
    const {
      catalog_sku,
      condition,
      language,
      finish,
      price,
      quantity,
      title,
      description,
      images,
      shipping_method,
      status,
    } = req.validatedBody

    const handle = toHandle(`${catalog_sku}-${condition}-${Date.now()}`)
    const variantSku = `${catalog_sku}-${condition}-${language}-${finish}`

    const productStatus = status === 'draft' ? ProductStatus.DRAFT : ProductStatus.PUBLISHED

    const { result: products } = await createProductsWorkflow(req.scope).run({
      input: {
        products: [
          {
            title,
            handle,
            description: description || undefined,
            is_giftcard: false,
            discountable: false,
            status: productStatus,
            thumbnail: images?.[0] || undefined,
            images: images?.length ? images.map((url) => ({ url })) : [],
            options: [
              {
                title: 'Condition',
                values: [condition],
              },
            ],
            variants: [
              {
                title: `${condition} Condition`,
                sku: variantSku,
                allow_backorder: false,
                manage_inventory: true,
                options: {
                  Condition: condition,
                },
                prices: [
                  {
                    currency_code: 'usd',
                    amount: price,
                  },
                ],
                metadata: {
                  catalog_sku,
                  condition,
                  language,
                  finish,
                  quantity,
                  seller_type: 'consumer',
                  shipping_method,
                },
              },
            ],
            metadata: {
              catalog_sku,
              seller_type: 'consumer',
              shipping_method,
              quantity,
            },
          },
        ],
        additional_data: {
          seller_id: seller.id,
        },
      },
    })

    const product = products[0]
    const variant = product.variants?.[0]

    logger.info(
      `[consumer-seller/listings] Created listing ${product.id} for seller ${seller.id}`
    )

    return res.status(201).json({
      success: true,
      data: {
        listing_id: product.id,
        title: product.title,
        handle: product.handle,
        status: product.status,
        thumbnail: product.thumbnail,
        variant_id: variant?.id,
        sku: variant?.sku,
        price,
        quantity,
        condition,
        shipping_method,
      },
    })
  } catch (error: any) {
    logger.error(`[consumer-seller/listings] Create error: ${error?.message}`)
    if (error?.type === 'not_found') {
      return res.status(404).json({
        success: false,
        message: 'Customer is not registered as a seller',
      })
    }
    return res.status(500).json({
      success: false,
      message: 'Failed to create listing',
    })
  }
}

