  rating: number
  reviewCount: number
}

// ─── Internal helpers ─────────────────────────────────────────────────────────

async function fetchCatalog(cardId: string): Promise<RawCatalogCard> {
  const response = await fetch(
    `${CUSTOMER_BACKEND_URL}/api/cards/${cardId}/details`
  )

  if (response.status === 404) {
    throw new CardNotFoundError(cardId)
  }

  if (!response.ok) {
    throw new Error(`Catalog fetch failed: ${response.status}`)
  }

  const body = await response.json()
  // customer-backend /cards/:id/details returns the card object at root level (not wrapped in { data })
  return (body.data ?? body) as RawCatalogCard
}

function buildCatalogSku(card: RawCatalogCard): string {
  const print = card.prints?.[0]
  const gameCode = card.game?.code ?? card.gameCode ?? ''
  const setCode = print?.set?.code ?? ''
  const collectorNumber = print?.number ?? ''
  return `${gameCode}-${setCode}-${collectorNumber}`
}

async function fetchListingsWithFallback(
  catalogSku: string
): Promise<{ listings: RawListing[]; unavailable: boolean }> {
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), LISTINGS_TIMEOUT_MS)

  try {
    const encodedSku = encodeURIComponent(catalogSku)
    const response = await fetch(
      `${BACKEND_STORE_URL}/store/cards/listings?catalog_sku=${encodedSku}`,
      { signal: controller.signal }
    )

    if (!response.ok) {
      return { listings: [], unavailable: true }
    }

    const body = await response.json()
    return { listings: (body.data as RawListing[]) ?? [], unavailable: false }
  } catch (err) {
    return { listings: [], unavailable: true }
  } finally {
    clearTimeout(timeout)
  }
}

async function fetchTrustBatch(
  sellerIds: string[]
): Promise<Record<string, TrustData>> {
  const response = await fetch(
    `${CUSTOMER_BACKEND_URL}/api/sellers/trust/batch`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sellerIds }),
    }
  )

  if (!response.ok) {
    throw new Error(`Trust batch fetch failed: ${response.status}`)
  }

  const body = await response.json()
  return (body.data as Record<string, TrustData>) ?? {}
}

function mergeListingsWithTrust(
  rawListings: RawListing[],
  trust: Record<string, TrustData>
): BackendListing[] {
  return rawListings.map(raw => {
    const trustData = trust[raw.seller_id]
    const listing: BackendListing = {
      id: raw.id,
      catalogSku: raw.catalog_sku,
      condition: raw.condition,
      language: raw.language,
      finish: raw.finish,
      price: raw.price,
      currency: raw.currency,
      quantity: raw.quantity,
      shippingMethod: raw.shipping_method,
      sellerId: raw.seller_id,
      sellerName: raw.seller_name,
      sellerType: raw.seller_type,
    }

    if (raw.shipping_cost !== undefined) {
      listing.shippingCost = raw.shipping_cost
    }
    if (raw.shipping_location !== undefined) {
      listing.shippingLocation = raw.shipping_location
    }
    if (trustData) {
      listing.sellerRating = trustData.rating
      listing.sellerReviewCount = trustData.reviewCount
    }

    return listing
  })
}

function sortListings(listings: BackendListing[]): BackendListing[] {
  return [...listings].sort((a, b) => {
    if (a.price !== b.price) return a.price - b.price
    return CONDITION_ORDER.indexOf(a.condition) - CONDITION_ORDER.indexOf(b.condition)
  })
}

function buildCardResponse(
  raw: RawCatalogCard
): CardDetailBFFResponse['card'] {
  // Build legality map from the first print's legality fields
  const print = raw.prints?.[0]
  const legality: Record<string, boolean> = {}

  if (print) {
    if (print.isLegalStandard !== undefined) legality['standard'] = print.isLegalStandard
    if (print.isLegalPioneer !== undefined) legality['pioneer'] = print.isLegalPioneer
    if (print.isLegalModern !== undefined) legality['modern'] = print.isLegalModern
    if (print.isLegalLegacy !== undefined) legality['legacy'] = print.isLegalLegacy
    if (print.isLegalVintage !== undefined) legality['vintage'] = print.isLegalVintage
    if (print.isLegalCommander !== undefined) legality['commander'] = print.isLegalCommander
    if (print.isLegalPauper !== undefined) legality['pauper'] = print.isLegalPauper
    if (print.isLegalBrawl !== undefined) legality['brawl'] = print.isLegalBrawl
    if (print.isLegalPokemonStandard !== undefined) legality['pokemonStandard'] = print.isLegalPokemonStandard
    if (print.isLegalPokemonExpanded !== undefined) legality['pokemonExpanded'] = print.isLegalPokemonExpanded
    if (print.isLegalPokemonUnlimited !== undefined) legality['pokemonUnlimited'] = print.isLegalPokemonUnlimited
    if (print.isLegalYugiohAdvanced !== undefined) legality['yugiohAdvanced'] = print.isLegalYugiohAdvanced
    if (print.isLegalYugiohTraditional !== undefined) legality['yugiohTraditional'] = print.isLegalYugiohTraditional
    if (print.isLegalOnePieceStandard !== undefined) legality['onePieceStandard'] = print.isLegalOnePieceStandard
  }

  // Convert date strings to Date objects
  const prints: Print[] = raw.prints.map(p => ({
    ...p,
    createdAt: new Date(p.createdAt),
    updatedAt: new Date(p.updatedAt),
    set: p.set
      ? { ...p.set, createdAt: new Date(p.set.createdAt), updatedAt: new Date(p.set.updatedAt) }
      : undefined,
  }))

  const sets: CardSet[] = raw.sets.map(s => ({
    ...s,
    createdAt: new Date(s.createdAt),
    updatedAt: new Date(s.updatedAt),
  }))

  return {
    ...raw,
    createdAt: new Date(raw.createdAt),
    updatedAt: new Date(raw.updatedAt),
    game: raw.game
      ? {
          ...raw.game,
          code: raw.game.code as 'MTG' | 'POKEMON' | 'YUGIOH' | 'OPTCG',
          createdAt: new Date(raw.game.createdAt),
          updatedAt: new Date(raw.game.updatedAt),
        }
      : undefined,
    prints,
    sets,
    legality,
  } as CardDetailBFFResponse['card']
}

// ─── Public API ───────────────────────────────────────────────────────────────

export async function fetchCardDetailBFF(
  cardId: string,
  catalogSkuOverride?: string
): Promise<CardDetailBFFResponse> {
  // Step 1: Catalog fetch — hard error on failure
  const rawCard = await fetchCatalog(cardId)

  // Step 2: Build catalogSku (or use override for re-fetch on print switch)
  const catalogSku = catalogSkuOverride ?? buildCatalogSku(rawCard)

  // Step 3: Fetch listings with graceful degradation
  const { listings: rawListings, unavailable } =
    await fetchListingsWithFallback(catalogSku)

  // Step 4: Fetch trust batch (deduped seller IDs) — only if there are listings
  let trust: Record<string, TrustData> = {}
  if (rawListings.length > 0) {
    const uniqueSellerIds = [...new Set(rawListings.map(l => l.seller_id))]
    try {
      trust = await fetchTrustBatch(uniqueSellerIds)
    } catch {
      // Trust failure is non-fatal — listings show without trust signals
    }
  }

  // Step 5: Merge, sort, and return
  const listings = sortListings(mergeListingsWithTrust(rawListings, trust))
  const card = buildCardResponse(rawCard)

  return { card, listings, listingsUnavailable: unavailable }
}

