 * description: "Returns all published listings for a given catalog_sku. Used by the storefront BFF to populate card detail pages."
 * parameters:
 *   - name: catalog_sku
 *     in: query
 *     required: true
 *     schema:
 *       type: string
 *     description: The catalog SKU (e.g. MTG-MKM-242)
 * responses:
 *   "200":
