  seller_id: string
  seller_name: string
  seller_type: 'consumer' | 'business'
}

export function mapVariantToListing(
  variant: RawVariant,
  catalogSku: string
): ListingRow {
  const meta = variant.metadata ?? {}
  const productMeta = variant.product?.metadata ?? {}

  const sellerTypeRaw = (meta.seller_type ?? productMeta.seller_type ?? 'consumer') as string
  const sellerType: 'consumer' | 'business' =
    sellerTypeRaw === 'business' || sellerTypeRaw === 'business_vendor' ? 'business' : 'consumer'

  return {
    id: variant.id,
    catalog_sku: catalogSku,
    condition: (meta.condition as string) ?? 'NM',
    language: ((meta.language as string) ?? 'en').toLowerCase(),
    finish: (meta.finish as string) ?? 'NORMAL',
    price: variant.prices?.[0]?.amount ?? 0,
    currency: variant.prices?.[0]?.currency_code ?? 'usd',
    quantity: Number(meta.quantity ?? 1),
    shipping_method: (meta.shipping_method as string) ?? 'standard',
    seller_id: variant.product?.seller_id ?? '',
    seller_name: (productMeta.seller_name as string) ?? '',
    seller_type: sellerType,
  }
}

