import { MedusaStoreRequest, MedusaResponse } from '@medusajs/framework/http'
import { ContainerRegistrationKeys } from '@medusajs/framework/utils'
import { mapVariantToListing } from './utils'

/**
 * @oas [get] /store/cards/listings
 * operationId: "GetCardListings"
 * summary: "Get public listings for a catalog SKU"
 * description: "Returns all published listings for a given catalog_sku. Used by the storefront BFF to populate card detail pages."
 * parameters:
 *   - name: catalog_sku
 *     in: query
 *     required: true
 *     schema:
 *       type: string
 *     description: The catalog SKU (e.g. MTG-MKM-242)
 * responses:
 *   "200":
 *     description: OK
 *   "400":
 *     description: Missing catalog_sku
 * tags:
 *   - Card Listings
 */
export const GET = async (req: MedusaStoreRequest, res: MedusaResponse) => {
  const rawSku = req.query.catalog_sku
  if (Array.isArray(rawSku)) {
    return res.status(400).json({ success: false, error: 'catalog_sku must be a single value' })
  }
  const catalogSku = rawSku as string | undefined

  if (!catalogSku?.trim()) {
    return res.status(400).json({
      success: false,
      error: 'catalog_sku query parameter is required',
    })
  }

  const logger = req.scope.resolve(ContainerRegistrationKeys.LOGGER)
  const query = req.scope.resolve(ContainerRegistrationKeys.QUERY)

  try {
    // Query product variants by catalog_sku stored in variant metadata.
    // MikroORM v6 supports JSONB containment queries via nested filter objects.
    const { data: variants } = await query.graph({
      entity: 'product_variant',
      fields: [
        'id',
        'sku',
        'metadata',
        'prices.amount',
        'prices.currency_code',
        'product.id',
        'product.status',
        'product.seller_id',
        'product.metadata',
      ],
      filters: {
        metadata: { catalog_sku: catalogSku },
      },
    })

    const listings = (variants as any[])
      .filter((v: any) => v.product?.status === 'published')
      .map((v: any) => mapVariantToListing(v, catalogSku))

    return res.json({ data: listings })
  } catch (error: any) {
    logger.error(
      `[store/cards/listings] Error fetching listings for ${catalogSku}: ${error?.message}`
    )
    return res.status(500).json({
      success: false,
      error: 'Failed to fetch listings',
    })
  }
}

